"""
# escript-template v20190523 / nutanix
# * author:       nutanix
# * version:      2019/06/04
# task_name:      PcMountNgt
# description:    This script mounts the Nutanix Guest Tools on the AHV
#                 virtual machine provisioned by Calm.
"""


import requests
from requests import exceptions
from requests.adapters import HTTPAdapter
from requests.packages.urllib3 import Retry, Timeout
from requests.packages.urllib3.exceptions import MaxRetryError


cluster_uuid = "@@{platform.status.cluster_reference.uuid}@@"
pc_ip = "@@{prism_central_ip}@@"
vm_uuid = "@@{platform.metadata.uuid}@@"
username = '@@{cred_prismcentral.username}@@'
password = '@@{cred_prismcentral.secret}@@'


def process_request(url, method, headers=None, username=None, password=None, auth=None, payload=None):

    if (username != None):
        auth = (username, password)

    session = requests.Session()
    # method_whitelist for Python 2.x
    # allowed_methods for Python 3.x
    retries = Retry(total=4, backoff_factor=1, method_whitelist=set({'GET'}), raise_on_status=False, status_forcelist=[403, 404, 413, 429, 500, 501, 502, 503, 504])
    adapter = HTTPAdapter(max_retries=retries)
    session.mount("http://", adapter)
    session.mount("https://", adapter)
    try:
        resp = session.request(
                method,
                url,
                headers=headers,
                auth=auth,
                data=payload,
                verify=False,
                timeout=Timeout(connect=3, read=60)
            )
        resp.raise_for_status()
    except exceptions.HTTPError as e:
        try:
            print("status code: {0}".format(resp.status_code))
        except:
            print("status code: None")
        try:
            print("reason: {0}".format(resp.reason))
        except:
            print("reason: None")
        try:
            print("text: {0}".format(resp.text))
        except:
            print("text: None")
        try:
            print("headers: {0}".format(resp.headers))
        except:
            print("headers: None")
        try:
            print("payload: {0}".format(resp.payload))
        except:
            print("payload: None")
        try:
            print("elapsed: {0}".format(resp.elapsed))
        except:
            print("elapsed: None")
        template = "An exception of type {0} occurred. Arguments:\n{1!r}"
        message = template.format(type(e).__name__, e.args)
        print(message)
        raise
    except MaxRetryError as e:
        template = "An exception of type {0} occurred. Arguments:\n{1!r}"
        message = template.format(type(e).__name__, e.args)
        print(message)
        raise
    except:
        raise

    try:
        resp = json.loads(resp.content)
    except:
        resp = resp.content

    return resp


def queryVm(vmUuid):

    method = 'GET'
    url = "{0}/vms/{1}".format(apiUrl, vmUuid)
    headers = {
        'Content-Type': 'application/json'
    }
    payload = json.dumps({})

    print("Making a {} API call to {}".format(method, url))

    resp = process_request(url, method, headers, payload=payload, username=username, password=password)

    print("Retrieved VM: {}".format(vmUuid))
    return resp


def updateVm(vmUuid, vmData):

    method = 'PUT'
    url = "{0}/vms/{1}".format(apiUrl, vmUuid)
    headers = {
        'Content-Type': 'application/json'
    }
    payload = {
        "spec": {
        },
        "metadata": {
        },
        "api_version": "3.1.0"
    }
    payload["spec"].update(
        vmData["spec"]
    )
    payload["metadata"].update(
        vmData["metadata"]
    )
    payload["spec"]["resources"].update(
        {
            "guest_tools": {
                "nutanix_guest_tools": {
                    "iso_mount_state": "MOUNTED",
                    "state": "ENABLED",
                    "enabled_capability_list": [
                        #"SELF_SERVICE_RESTORE"
                    ]
                }
            }
        }
    )
    payload = json.dumps(payload)

    print("Making a {} API call to {}".format(method, url))

    resp = process_request(url, method, headers, payload=payload, username=username, password=password)

    print("Mounting and enabling NGT on VM: {}".format(vmUuid))
    return resp["status"]["execution_context"]["task_uuid"]


def queryTask(taskUuid):

    method = 'GET'
    url = "{0}/tasks/{1}".format(apiUrl, taskUuid)
    headers = {
        'Content-Type': 'application/json'
    }
    payload = json.dumps({})

    print("Making a {} API call to {}".format(method, url))

    resp = process_request(url, method, headers, payload=payload, username=username, password=password)

    print("Retrieved Task: {}".format(taskUuid))
    return resp["status"]


def enableNgt(vm_uuid):
    retrieved_vm = queryVm(vm_uuid)
    task_uuid = updateVm(vm_uuid, retrieved_vm)

    return task_uuid


apiUrl = "https://{0}:9440/api/nutanix/v3".format(pc_ip)
task_uuid = enableNgt(vm_uuid)
i = 1
while (True):
    update_task = queryTask(task_uuid)
    if update_task == "FAILED" and i == 3:
        print("Unable to enable and mount NGT...")
        exit(1)
    elif update_task == "RUNNING" or update_task == "QUEUED":
        sleep(5)
        continue
    elif update_task == "SUCCEEDED":
        print("Mounted and enabled NGT on VM: {}".format(vm_uuid))
        break
    elif update_task == "FAILED":
        print("FAILURE: Attempting to mount and enable NGT again...")
        i = i + 1
        sleep(15)
        task_uuid = enableNgt(vm_uuid)
        continue
    else:
        print("Unknown task status code: {0}".format(update_task))
        exit(1)

